TARGET_FUNCTIONS = ['onex_parser_status_live', 'onex_parser_start', 'onex_parser_launch', 'onex_parser_pause', 'onex_parser_clear', 'onex_parser_run', 'onex_parser_confirm', 'onex_parser_alias', 'api_onex_agent_job', 'api_onex_agent_heartbeat', 'api_onex_agent_schedule_start', 'api_onex_agent_job_complete', 'api_onex_agent_upload_session', 'api_onex_parser_import_rows', 'chatterfy_parser_status_live', 'toggle_chatterfy_parser']

MODULE_SOURCE = 'def onex_parser_status_live(request: Request):\n    user = get_current_user(request)\n    if not user:\n        raise HTTPException(status_code=401, detail="Unauthorized")\n    enforce_page_access(user, "onexparser")\n    payload = dict(get_onex_agent_state())\n    payload["account_statuses"] = build_onex_account_statuses(payload)\n    return JSONResponse(payload)\n\ndef onex_parser_start(\n    request: Request,\n    account_id: str = Form(...),\n):\n    user = get_current_user(request)\n    if not user:\n        raise HTTPException(status_code=401, detail="Unauthorized")\n    enforce_page_access(user, "onexparser")\n    try:\n        account = get_onexbet_account(account_id)\n        if not account:\n            raise ValueError("Аккаунт 1xPartners не найден.")\n        queue_onex_agent_job("open_login", account_id=account_id)\n        payload = save_onex_agent_state(\n            status="waiting_for_user",\n            connected=bool(get_onex_agent_state().get("connected")),\n            current_account=account["id"],\n            current_account_label=account["label"],\n            message="Задача отправлена локальному агенту. Когда агент откроет 1x у тебя на компьютере, пройди captcha и вернись сюда.",\n            last_error="",\n        )\n        return JSONResponse(payload)\n    except ValueError as exc:\n        return JSONResponse({"status": "error", "message": safe_text(exc), "error": safe_text(exc)}, status_code=400)\n    except RuntimeError as exc:\n        payload = get_onex_agent_state()\n        payload["status"] = "busy"\n        payload["message"] = safe_text(exc)\n        payload["error"] = safe_text(exc)\n        return JSONResponse(payload, status_code=409)\n\ndef onex_parser_launch(\n    request: Request,\n    account_id: str = Form(...),\n):\n    user = get_current_user(request)\n    if not user:\n        raise HTTPException(status_code=401, detail="Unauthorized")\n    enforce_page_access(user, "onexparser")\n    try:\n        all_accounts = get_onexbet_accounts()\n        account_ids = [item["id"] for item in all_accounts]\n        if not account_ids:\n            raise ValueError("Аккаунты 1xPartners не найдены.")\n        start_onex_server_first_flow(account_ids)\n        payload = save_onex_agent_state(\n            status="running",\n            connected=bool(get_onex_agent_state().get("connected")),\n            paused=False,\n            current_account="__all__",\n            current_account_label="All cabinets",\n            message=f"Сервер начал тихую выгрузку сразу для {len(account_ids)} кабинетов. Локальное окно откроется только если где-то понадобится captcha.",\n            job_status="running",\n            job_message="Server-first all-cabinets flow для 1x Parser.",\n            last_error="",\n        )\n        return JSONResponse(payload)\n    except ValueError as exc:\n        return JSONResponse({"status": "error", "message": safe_text(exc), "error": safe_text(exc)}, status_code=400)\n    except RuntimeError as exc:\n        payload = get_onex_agent_state()\n        payload["status"] = safe_text(payload.get("status")) or "running"\n        payload["message"] = "Парсер уже запущен. Нажми Pause Parser, если хочешь остановить текущий процесс."\n        payload["error"] = safe_text(exc)\n        return JSONResponse(payload, status_code=409)\n\ndef onex_parser_pause(\n    request: Request,\n    account_id: str = Form(...),\n):\n    user = get_current_user(request)\n    if not user:\n        raise HTTPException(status_code=401, detail="Unauthorized")\n    enforce_page_access(user, "onexparser")\n    clear_onex_agent_job()\n    append_onex_agent_log("Парсер поставлен на паузу.", kind="done")\n    payload = save_onex_agent_state(\n        status="idle",\n        paused=True,\n        message="Парсер на паузе. Можно снова нажать Start Parser.",\n        job_status="idle",\n        job_message="",\n        last_error="",\n    )\n    return JSONResponse(payload)\n\ndef onex_parser_clear(\n    request: Request,\n    account_id: str = Form(...),\n):\n    user = get_current_user(request)\n    if not user:\n        raise HTTPException(status_code=401, detail="Unauthorized")\n    enforce_page_access(user, "onexparser")\n    try:\n        queue_onex_agent_job("clear_session", account_id=account_id)\n        account = get_onexbet_account(account_id) or {}\n        return JSONResponse(save_onex_agent_state(\n            status="running",\n            current_account=safe_text(account.get("id")),\n            current_account_label=safe_text(account.get("label")),\n            message="Отправил локальному агенту команду очистить профиль и сессию 1x.",\n            session_saved=False,\n            profile_exists=False,\n            last_error="",\n        ))\n    except ValueError as exc:\n        return JSONResponse({"status": "error", "message": safe_text(exc), "error": safe_text(exc)}, status_code=400)\n    except RuntimeError as exc:\n        payload = get_onex_agent_state()\n        payload["status"] = "busy"\n        payload["message"] = safe_text(exc)\n        payload["error"] = safe_text(exc)\n        return JSONResponse(payload, status_code=409)\n\ndef onex_parser_run(\n    request: Request,\n    account_id: str = Form(...),\n):\n    user = get_current_user(request)\n    if not user:\n        raise HTTPException(status_code=401, detail="Unauthorized")\n    enforce_page_access(user, "onexparser")\n    try:\n        agent_state = get_onex_agent_state()\n        if not agent_state.get("session_saved"):\n            raise ValueError("Сначала подключи локальный агент и подтверди сессию через I Passed Captcha.")\n        account = get_onexbet_account(account_id)\n        if not account:\n            raise ValueError("Аккаунт 1xPartners не найден.")\n        queue_onex_agent_job("run_export", account_id=account_id, payload=get_current_onex_export_plan())\n        payload = save_onex_agent_state(\n            status="running",\n            current_account=account["id"],\n            current_account_label=account["label"],\n            message="Задача выгрузки отправлена локальному агенту.",\n            job_status="pending",\n            job_message="Ожидаю локальный экспорт игроков из 1x.",\n            last_error="",\n        )\n        return JSONResponse(payload)\n    except ValueError as exc:\n        return JSONResponse({"status": "error", "message": safe_text(exc), "error": safe_text(exc)}, status_code=400)\n    except RuntimeError as exc:\n        payload = get_onex_agent_state()\n        payload["status"] = "busy"\n        payload["message"] = safe_text(exc)\n        payload["error"] = safe_text(exc)\n        return JSONResponse(payload, status_code=409)\n\ndef onex_parser_confirm(\n    request: Request,\n    account_id: str = Form(...),\n):\n    user = get_current_user(request)\n    if not user:\n        raise HTTPException(status_code=401, detail="Unauthorized")\n    enforce_page_access(user, "onexparser")\n    try:\n        account = get_onexbet_account(account_id)\n        if not account:\n            raise ValueError("Аккаунт 1xPartners не найден.")\n        queue_onex_agent_job("check_auth", account_id=account_id)\n        payload = save_onex_agent_state(\n            status="running",\n            current_account=account["id"],\n            current_account_label=account["label"],\n            message="Попросил локальный агент проверить, завершён ли вход после captcha.",\n            job_status="pending",\n            job_message="Ожидаю проверку локальной сессии 1x.",\n            last_error="",\n        )\n        return JSONResponse(payload)\n    except ValueError as exc:\n        return JSONResponse({"status": "error", "message": safe_text(exc), "error": safe_text(exc)}, status_code=400)\n    except RuntimeError as exc:\n        payload = get_onex_agent_state()\n        payload["status"] = "busy"\n        payload["message"] = safe_text(exc)\n        payload["error"] = safe_text(exc)\n        return JSONResponse(payload, status_code=409)\n\ndef onex_parser_alias(request: Request):\n    return RedirectResponse(url="/1x-parser", status_code=307)\n\ndef api_onex_agent_job(\n    api_key: str = Query(default=""),\n    api_key_header: str = Header(default="", alias="api-key"),\n    api_key_alt_header: str = Header(default="", alias="api_key"),\n):\n    require_onex_agent_api_key(api_key, api_key_header, api_key_alt_header)\n    state = save_onex_agent_state(\n        connected=True,\n        status=safe_text(get_onex_agent_state().get("status")) or "idle",\n        message=safe_text(get_onex_agent_state().get("message")) or "Локальный агент подключён.",\n        last_seen_at=datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%S"),\n    )\n    job = get_onex_agent_job()\n    return JSONResponse({"job": job, "state": state, "accounts": get_onexbet_accounts()})\n\nasync def api_onex_agent_heartbeat(\n    request: Request,\n    api_key: str = Query(default=""),\n    api_key_header: str = Header(default="", alias="api-key"),\n    api_key_alt_header: str = Header(default="", alias="api_key"),\n):\n    require_onex_agent_api_key(api_key, api_key_header, api_key_alt_header)\n    payload = await request.json()\n    state = save_onex_agent_state(\n        connected=True,\n        last_seen_at=datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%S"),\n        status=safe_text(payload.get("status")) or safe_text(get_onex_agent_state().get("status")) or "idle",\n        message=safe_text(payload.get("message")) or safe_text(get_onex_agent_state().get("message")) or "Локальный агент подключён.",\n        current_account=safe_text(payload.get("current_account")),\n        current_account_label=safe_text(payload.get("current_account_label")),\n        job_status=safe_text(payload.get("job_status")) or safe_text(get_onex_agent_state().get("job_status")) or "idle",\n        job_message=safe_text(payload.get("job_message")),\n        session_saved=bool(payload.get("session_saved")),\n        profile_exists=bool(payload.get("profile_exists")),\n        last_error=safe_text(payload.get("last_error")),\n        agent_version=safe_text(payload.get("agent_version")),\n    )\n    return JSONResponse(state)\n\nasync def api_onex_agent_schedule_start(\n    request: Request,\n    api_key: str = Query(default=""),\n    api_key_header: str = Header(default="", alias="api-key"),\n    api_key_alt_header: str = Header(default="", alias="api_key"),\n):\n    require_onex_agent_api_key(api_key, api_key_header, api_key_alt_header)\n    payload = await request.json()\n    requested_ids = [safe_text(item) for item in (payload.get("account_ids") or []) if safe_text(item)]\n    if requested_ids:\n        available = {item["id"] for item in get_onexbet_accounts()}\n        account_ids = [item for item in requested_ids if item in available]\n    else:\n        account_ids = [item["id"] for item in get_onexbet_accounts()]\n    if not account_ids:\n        raise HTTPException(status_code=400, detail="Unknown account")\n    current_job = get_onex_agent_job()\n    if safe_text(current_job.get("status")) == "pending":\n        return JSONResponse(get_onex_agent_state())\n    trigger = safe_text(payload.get("trigger")) or "scheduled"\n    if len(account_ids) == 1:\n        queue_onex_agent_job("start_full_flow", account_id=account_ids[0], payload=get_current_onex_export_plan())\n    else:\n        queue_onex_agent_job("start_multi_flow", payload={"export_plan": get_current_onex_export_plan()}, account_ids=account_ids)\n    state = save_onex_agent_state(\n        status="waiting_for_user",\n        connected=True,\n        current_account="__all__" if len(account_ids) > 1 else account_ids[0],\n        current_account_label="All cabinets" if len(account_ids) > 1 else safe_text((get_onexbet_account(account_ids[0]) or {}).get("label")),\n        message=f"Автозапуск {trigger} поставлен в очередь для {len(account_ids)} кабинетов.",\n        job_status="pending",\n        job_message=f"Ожидаю локальный запуск по расписанию {trigger}.",\n        last_error="",\n    )\n    append_onex_agent_log(f"Автозапуск {trigger}: поставил задачу для {len(account_ids)} кабинетов.", kind="start")\n    return JSONResponse(state)\n\nasync def api_onex_agent_job_complete(\n    request: Request,\n    api_key: str = Query(default=""),\n    api_key_header: str = Header(default="", alias="api-key"),\n    api_key_alt_header: str = Header(default="", alias="api_key"),\n):\n    require_onex_agent_api_key(api_key, api_key_header, api_key_alt_header)\n    payload = await request.json()\n    job = get_onex_agent_job()\n    clear_onex_agent_job()\n    completion_status = safe_text(payload.get("status")).lower()\n    completion_message = safe_text(payload.get("message")) or "Локальная задача завершена."\n    if completion_message:\n        append_onex_agent_log(\n            completion_message,\n            kind="error" if completion_status == "error" else ("done" if completion_status in {"ready", "idle"} else "info"),\n        )\n    state = save_onex_agent_state(\n        connected=True,\n        last_seen_at=datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%S"),\n        status=safe_text(payload.get("status")) or "idle",\n        message=completion_message,\n        current_account=safe_text(payload.get("current_account")) or safe_text(job.get("account_id")),\n        current_account_label=safe_text(payload.get("current_account_label")) or safe_text(job.get("account_label")),\n        job_status="idle",\n        job_message="",\n        session_saved=bool(payload.get("session_saved")),\n        profile_exists=bool(payload.get("profile_exists")),\n        last_error=safe_text(payload.get("last_error")),\n    )\n    return JSONResponse(state)\n\nasync def api_onex_agent_upload_session(\n    request: Request,\n    api_key: str = Query(default=""),\n    api_key_header: str = Header(default="", alias="api-key"),\n    api_key_alt_header: str = Header(default="", alias="api_key"),\n):\n    require_onex_agent_api_key(api_key, api_key_header, api_key_alt_header)\n    payload = await request.json()\n    account_id = safe_text(payload.get("account_id"))\n    if not get_onexbet_account(account_id):\n        raise HTTPException(status_code=400, detail="Unknown account")\n    storage_state = payload.get("storage_state")\n    cookies = payload.get("cookies")\n    status_info = save_onexbet_server_session(account_id, storage_state, cookies)\n    ensure_onexbet_server_keepalive(account_id)\n    append_onex_agent_log(f"Локальный агент синхронизировал server session для {account_id}.", kind="success")\n    return JSONResponse({"ok": True, "account_id": account_id, **status_info})\n\nasync def api_onex_parser_import_rows(\n    request: Request,\n    api_key: str = Query(default=""),\n    api_key_header: str = Header(default="", alias="api-key"),\n    api_key_alt_header: str = Header(default="", alias="api_key"),\n):\n    require_onex_agent_api_key(api_key, api_key_header, api_key_alt_header)\n    payload = await request.json()\n    account_id = safe_text(payload.get("account_id"))\n    account = get_onexbet_account(account_id)\n    if not account:\n        raise HTTPException(status_code=400, detail="Unknown account")\n    source_name = safe_text(payload.get("source_name"))\n    rows_payload = payload.get("rows") or []\n    rows = onex_parser_rows_from_payload(rows_payload)\n    import_onex_parser_rows_async(account, source_name, rows)\n    state = save_onex_agent_state(\n        connected=True,\n        status="running",\n        message=f"Принял {len(rows)} строк на фоновый импорт в 1x Parser.",\n        current_account=account_id,\n        current_account_label=safe_text(account.get("label")),\n        job_status="running",\n        job_message="Фоновая запись строк в 1x Parser.",\n        session_saved=True,\n        profile_exists=True,\n        last_count=len(rows),\n        period_label=safe_text(payload.get("period_label")),\n        date_start=safe_text(payload.get("date_start")),\n        date_end=safe_text(payload.get("date_end")),\n        last_source_name=source_name,\n        last_seen_at=datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%S"),\n    )\n    clear_onex_agent_job()\n    return JSONResponse({"ok": True, "count": len(rows), "state": state})\n\ndef chatterfy_parser_status_live(request: Request):\n    user = get_current_user(request)\n    if not user:\n        raise HTTPException(status_code=401, detail="Unauthorized")\n    enforce_page_access(user, "chatterfyparser")\n    return JSONResponse(chatterfy_parser_runtime_payload())\n\ndef toggle_chatterfy_parser(\n    request: Request,\n    bot_url: str = Form(...),\n    period_view: str = Form(default="period"),\n    period_label: str = Form(default=""),\n):\n    user = get_current_user(request)\n    if not user:\n        return auth_redirect_response()\n    enforce_page_access(user, "chatterfyparser")\n\n    existing_config = get_chatterfy_parser_config()\n    form_data = build_chatterfy_parser_config_payload(\n        bot_url=bot_url,\n        period_view=period_view,\n        period_label=period_label,\n        auto_sync_enabled=bool(existing_config.get("auto_sync_enabled")),\n        existing_config=existing_config,\n    )\n    bot_id = extract_chatterfy_bot_id(bot_url)\n    if not bot_id:\n        return HTMLResponse(\n            chatterfy_parser_page_html(user, [], form_data=form_data, period_view=safe_text(form_data.get("period_view")) or "period", period_label=safe_text(form_data.get("period_label")), error_text="Invalid Chatterfy Users URL. Expected format: /bots/<bot_id>/users"),\n            status_code=400,\n        )\n\n    try:\n        is_active = bool(existing_config.get("auto_sync_enabled")) or safe_text(existing_config.get("sync_state")) in {"running", "pause_pending", "idle"}\n        if is_active:\n            updated = dict(form_data)\n            updated["auto_sync_enabled"] = True\n            updated["sync_state"] = "pause_pending"\n            save_chatterfy_parser_config(updated)\n            chatterfy_parser_append_log("Нажата Пауза. Делаю последнюю выгрузку и после этого остановлю автосинк.", kind="info", config=updated)\n            if not CHATTERFY_SYNC_LOCK.locked():\n                run_chatterfy_parser_sync_async(initiated_by="pause")\n            success_message = "Пауза принята. Парсер сделает последнюю выгрузку и остановится."\n        else:\n            updated = dict(form_data)\n            updated["auto_sync_enabled"] = True\n            updated["sync_state"] = "idle"\n            save_chatterfy_parser_config(updated)\n            chatterfy_parser_append_log(f"Нажат Start. Включаю штатный режим для периода {safe_text(form_data.get(\'period_label\'))} и запускаю первую выгрузку.", kind="success", config=updated)\n            if not CHATTERFY_SYNC_LOCK.locked():\n                run_chatterfy_parser_sync_async(initiated_by="start")\n            success_message = f"Автосинк включён для периода {safe_text(form_data.get(\'period_label\'))}. Первая выгрузка уже запущена, дальше обновление будет раз в час."\n        return RedirectResponse(\n            url=(\n                f"/chatterfy-parser?bot_url={quote_plus(build_chatterfy_users_url(bot_id))}"\n                f"&period_view={quote_plus(safe_text(form_data[\'period_view\']) or \'period\')}"\n                f"&period_label={quote_plus(safe_text(form_data[\'period_label\']))}"\n                f"&message={quote_plus(success_message)}"\n            ),\n            status_code=303,\n        )\n    except Exception as exc:\n        return HTMLResponse(\n            chatterfy_parser_page_html(user, [], form_data=form_data, period_view=safe_text(form_data.get("period_view")) or "period", period_label=safe_text(form_data.get("period_label")), error_text=f"Could not import Chatterfy data: {exc}"),\n            status_code=400,\n        )\n\n'


def bind_domain_actions(ctx):
    scope = dict(ctx)
    exec(MODULE_SOURCE, scope)
    return {name: scope[name] for name in TARGET_FUNCTIONS}
